INSERT INTO `question_bank` VALUES (1,'请你做一个自我介绍','结合岗位要求，突出个人优势、项目经验和职业规划，控制在2-3分钟',4,NULL,NULL,'easy','system',0,'自我介绍,通用',NULL,'2026-03-12 09:54:35.505894','2026-03-12 09:54:35.505894','open',NULL),(2,'请举一个你在团队中解决冲突的例子','使用STAR法则：描述情境→任务→行动→结果，体现沟通和协调能力',4,NULL,NULL,'medium','system',0,'团队合作,STAR',NULL,'2026-03-12 09:54:35.506994','2026-03-12 09:54:35.506994','open',NULL),(3,'说说你最有成就感的一个项目','选择与目标岗位相关的项目，重点描述你的角色、技术选型、遇到的挑战和最终成果',3,NULL,NULL,'medium','system',0,'项目经验',NULL,'2026-03-12 09:54:35.507909','2026-03-12 09:54:35.507909','open',NULL),(4,'HashMap 的底层实现原理是什么？','数组+链表/红黑树，hash计算→取模定位→处理冲突，JDK1.8链表超8转红黑树',2,'字节跳动',NULL,'medium','system',0,'Java,数据结构',NULL,'2026-03-12 09:54:35.508979','2026-03-12 09:54:35.508979','open',NULL),(5,'TCP 三次握手和四次挥手的过程？','三次握手：SYN→SYN+ACK→ACK；四次挥手：FIN→ACK→FIN→ACK，TIME_WAIT等待2MSL',2,NULL,NULL,'medium','system',0,'网络,计算机基础',NULL,'2026-03-12 09:54:35.510094','2026-03-12 09:54:35.510094','open',NULL),(6,'如何设计一个短链接系统？','哈希/自增ID→Base62编码，数据库存储映射关系，缓存热点数据，301/302重定向',5,NULL,NULL,'hard','system',0,'系统设计,架构',NULL,'2026-03-12 09:54:35.511018','2026-03-12 09:54:35.511018','open',NULL),(7,'你的职业规划是什么？','短期（1-2年）：深入技术、独立负责模块；中期（3-5年）：成为技术骨干；长期：技术管理或专家路线',4,NULL,NULL,'easy','system',0,'职业规划,通用',NULL,'2026-03-12 09:54:35.511862','2026-03-12 09:54:35.511862','open',NULL),(8,'描述一个你面对压力的时候，你是怎么处理的？','用具体例子说明，展示情绪管理和问题解决能力',1,'宝洁',NULL,'medium','system',0,'宝洁八大问',NULL,'2026-03-12 09:54:35.513298','2026-03-12 09:54:35.513298','open',NULL),(9,'Redis 和 MySQL 数据一致性如何保证？','延迟双删、先更新DB再删缓存、消息队列异步更新、设置合理过期时间',2,'美团',NULL,'hard','system',0,'Redis,数据库,一致性',NULL,'2026-03-12 09:54:35.514130','2026-03-12 09:54:35.514130','open',NULL),(10,'浏览器输入URL到页面显示的全过程？','DNS解析→TCP连接→发送HTTP请求→服务器处理→返回响应→浏览器解析渲染(DOM→CSSOM→Render Tree→Layout→Paint)',2,NULL,NULL,'medium','system',0,'浏览器,前端,网络',NULL,'2026-03-12 09:54:35.514921','2026-03-12 09:54:35.514921','open',NULL),(11,'请举一个你领导团队完成一项任务的例子','使用STAR法则，描述团队规模、你作为leader做了什么决策、如何分配任务、遇到什么困难、如何解决、最终结果如何。注意突出你的领导力和决策力。',1,'宝洁',NULL,'medium','system',0,'领导力,宝洁八大问',NULL,'2026-03-14 11:35:48.886338','2026-03-14 11:35:48.886338','open',NULL),(12,'请举一个你说服别人的例子','先讲清楚背景和分歧点，然后描述你用了什么策略（数据说服、共情、利益分析等），最后对方被说服后的结果和反馈。',1,'宝洁',NULL,'medium','system',0,'沟通能力,宝洁八大问',NULL,'2026-03-14 11:35:48.898457','2026-03-14 11:35:48.898457','open',NULL),(13,'请举一个你改变了某个流程或方法的例子','描述你发现问题的过程、提出的改进方案、推动变革中遇到的阻力、最终效果（最好有量化数据）。',1,'宝洁',NULL,'medium','system',0,'创新能力,宝洁八大问',NULL,'2026-03-14 11:35:48.899633','2026-03-14 11:35:48.899633','open',NULL),(14,'请举一个你面对困难/挑战时如何处理的例子','描述困难的具体表现、你的分析和应对策略、过程中你学到了什么、最终如何克服。',1,'宝洁',NULL,'medium','system',0,'抗压能力,宝洁八大问',NULL,'2026-03-14 11:35:48.900795','2026-03-14 11:35:48.900795','open',NULL),(15,'请举一个你分析复杂问题并做出决策的例子','描述问题的复杂性（多因素交织、信息不完整等），你的分析框架（如优先级矩阵、SWOT），最终决策和依据。',1,'宝洁',NULL,'hard','system',0,'分析能力,宝洁八大问',NULL,'2026-03-14 11:35:48.902516','2026-03-14 11:35:48.902516','open',NULL),(16,'请举一个你与他人合作完成任务的例子','重点描述团队构成、你在团队中的角色、如何协调不同意见、如何确保团队高效运作。',1,'宝洁',NULL,'easy','system',0,'团队合作,宝洁八大问',NULL,'2026-03-14 11:35:48.903649','2026-03-14 11:35:48.903649','open',NULL),(17,'请举一个你设定目标并成功达成的例子','描述目标是什么、为什么设定这个目标、你制定的计划和执行步骤、中途的调整、最终的达成情况。',1,'宝洁',NULL,'easy','system',0,'目标导向,宝洁八大问',NULL,'2026-03-14 11:35:48.904765','2026-03-14 11:35:48.904765','open',NULL),(18,'如果用三个词形容自己，你会选哪三个？','选择与岗位相关的特质，每个词配一个简短的例子来支撑。如\"学习力强\"可举快速上手新技术的例子。',4,NULL,NULL,'easy','system',0,'自我认知,通用',NULL,'2026-03-14 11:35:48.905730','2026-03-14 11:35:48.905730','open',NULL),(19,'你最大的优点和缺点分别是什么？','优点要与岗位要求匹配并举例证明；缺点要真实但不致命，且要说明你正在如何改进。',4,NULL,NULL,'easy','system',0,'自我认知,通用',NULL,'2026-03-14 11:35:48.906800','2026-03-14 11:35:48.906800','open',NULL),(20,'为什么选择我们公司？','从行业前景、公司文化、业务方向、技术栈等角度回答，体现你做过功课。避免说\"为了学习\"这种被动表达。',4,NULL,NULL,'easy','system',0,'求职动机,通用',NULL,'2026-03-14 11:35:48.908377','2026-03-14 11:35:48.908377','open',NULL),(21,'你为什么选择这个岗位？','结合自己的专业背景、兴趣、能力和岗位JD来回答。突出你的经历与岗位的匹配度。',4,NULL,NULL,'easy','system',0,'求职动机,通用',NULL,'2026-03-14 11:35:48.909588','2026-03-14 11:35:48.909588','open',NULL),(22,'描述一次你在时间紧迫的情况下高效完成任务的经历','Situation: 描述紧迫的背景。Task: 你需要完成什么。Action: 你采取了什么策略（如优先级排序、任务拆分、加班等）。Result: 最终按时完成，质量如何。',4,NULL,NULL,'medium','system',0,'时间管理,STAR',NULL,'2026-03-14 11:35:48.910536','2026-03-14 11:35:48.910536','open',NULL),(23,'描述一次你犯错后如何处理的经历','真诚地描述错误，重点放在你发现错误后采取的补救措施、从中学到的教训、以及后续如何避免类似错误。',4,NULL,NULL,'medium','system',0,'问题解决,STAR',NULL,'2026-03-14 11:35:48.911401','2026-03-14 11:35:48.911401','open',NULL),(24,'描述一次你帮助别人的经历','展示你的同理心和团队精神。描述你为什么愿意帮助、如何帮助、帮助的效果。',4,NULL,NULL,'easy','system',0,'同理心,STAR',NULL,'2026-03-14 11:35:48.912267','2026-03-14 11:35:48.912267','open',NULL),(25,'描述一次你不得不学习新东西来解决问题的经历','突出你的学习能力。描述学习了什么、学习方法、花了多长时间、最终如何应用到实际问题中。',4,NULL,NULL,'medium','system',0,'学习能力,STAR',NULL,'2026-03-14 11:35:48.913060','2026-03-14 11:35:48.913060','open',NULL),(26,'描述一次你收到负面反馈后如何应对的经历','展示你的成长心态。描述反馈内容、你的感受和理性分析、采取的改进措施、后续改进效果。',4,NULL,NULL,'medium','system',0,'成长心态,STAR',NULL,'2026-03-14 11:35:48.914144','2026-03-14 11:35:48.914144','open',NULL),(27,'你未来5年的规划是什么？','分阶段描述：1-2年深入技术/业务，3-5年成为领域专家或team lead。要与目标公司的发展路径吻合。',4,NULL,NULL,'easy','system',0,'职业规划',NULL,'2026-03-14 11:35:48.915010','2026-03-14 11:35:48.915010','open',NULL),(28,'你期望的工作环境是怎样的？','描述你理想的团队氛围、技术氛围、管理风格等，但要与目标公司的文化相匹配。',4,NULL,NULL,'easy','system',0,'职业规划,企业文化',NULL,'2026-03-14 11:35:48.915938','2026-03-14 11:35:48.915938','open',NULL),(29,'你的薪资期望是多少？','可以给一个范围，参考市场行情和自身能力。可以说\"更看重发展机会，希望薪资能体现我的能力和贡献\"。',4,NULL,NULL,'easy','system',0,'薪资谈判',NULL,'2026-03-14 11:35:48.916709','2026-03-14 11:35:48.916709','open',NULL),(30,'如果你和直属领导意见不一致，你会怎么做？','先充分表达自己的观点和依据，认真倾听领导的考虑因素。如果依然有分歧，可以请求用数据验证，最终尊重领导决策并全力执行。',6,NULL,NULL,'medium','system',0,'情景模拟,沟通',NULL,'2026-03-14 11:35:48.917588','2026-03-14 11:35:48.917588','open',NULL),(31,'如果项目即将上线但发现了一个重要bug，你会怎么做？','评估bug严重性和修复成本。如果影响核心功能，建议推迟上线并紧急修复；如果影响有限，可以先上线并在下个版本修复。同时通知相关人员。',6,NULL,NULL,'medium','system',0,'情景模拟,应急处理',NULL,'2026-03-14 11:35:48.918375','2026-03-14 11:35:48.918375','open',NULL),(32,'如果让你负责一个你不熟悉的领域，你会怎么做？','快速学习：查文档、看代码、向有经验的同事请教。制定学习计划，边学边做，定期总结。',6,NULL,NULL,'easy','system',0,'情景模拟,学习能力',NULL,'2026-03-14 11:35:48.919291','2026-03-14 11:35:48.919291','open',NULL),(33,'数组和链表的区别？各自适用场景？','数组：连续内存，O(1)随机访问，O(n)插入删除。链表：非连续内存，O(n)访问，O(1)插入删除。数组适合频繁查询，链表适合频繁增删。',4,NULL,NULL,'easy','system',0,'数据结构,基础',NULL,'2026-03-14 11:35:48.920536','2026-03-14 11:35:48.920536','open',NULL),(34,'二叉树的前序、中序、后序遍历原理？','前序：根→左→右；中序：左→根→右；后序：左→右→根。递归和迭代两种实现方式。中序遍历BST得到有序序列。',4,NULL,NULL,'easy','system',0,'数据结构,二叉树',NULL,'2026-03-14 11:35:48.921505','2026-03-14 11:35:48.921505','open',NULL),(35,'快速排序的原理和时间复杂度？','选择基准元素，将数组分为两部分（小于基准和大于基准），递归排序。平均O(nlogn)，最坏O(n²)。优化：随机选择基准、三数取中。',4,NULL,NULL,'medium','system',0,'算法,排序',NULL,'2026-03-14 11:35:48.922430','2026-03-14 11:35:48.922430','open',NULL),(36,'什么是动态规划？举一个例子','将大问题分解为重叠子问题，通过保存子问题的解来避免重复计算。典型例子：爬楼梯(dp[i]=dp[i-1]+dp[i-2])、0-1背包、最长公共子序列。',4,NULL,NULL,'hard','system',0,'算法,动态规划',NULL,'2026-03-14 11:35:48.923222','2026-03-14 11:35:48.923222','open',NULL),(37,'堆（优先队列）的原理和应用场景？','完全二叉树，大顶堆parent>=child，小顶堆parent<=child。插入和删除O(logn)，取顶O(1)。应用：Top-K问题、任务调度、Dijkstra算法。',4,NULL,NULL,'medium','system',0,'数据结构,堆',NULL,'2026-03-14 11:35:48.923863','2026-03-14 11:35:48.923863','open',NULL),(38,'B+树和B树的区别？为什么MySQL用B+树？','B+树数据只在叶节点，叶节点有链表串联。优势：1)非叶节点能存更多key减少IO 2)叶节点链表支持范围查询 3)查询性能更稳定。',4,NULL,NULL,'hard','system',0,'数据结构,数据库',NULL,'2026-03-14 11:35:48.924503','2026-03-14 11:35:48.924503','open',NULL),(39,'如何判断链表是否有环？','快慢指针法：slow每次走1步，fast每次走2步。如果有环，fast终会追上slow。判断入环点：相遇后，一个指针回到头，两者同速前进，再次相遇即入环点。',4,NULL,NULL,'medium','system',0,'算法,链表',NULL,'2026-03-14 11:35:48.925452','2026-03-14 11:35:48.925452','open',NULL),(40,'HTTP和HTTPS的区别？','HTTPS = HTTP + SSL/TLS。区别：1)加密传输 2)需要证书 3)端口443 vs 80 4)性能略低但更安全 5)防止中间人攻击。',4,NULL,NULL,'easy','system',0,'网络,HTTP',NULL,'2026-03-14 11:35:48.926392','2026-03-14 11:35:48.926392','open',NULL),(41,'HTTP/1.1、HTTP/2、HTTP/3的主要区别？','HTTP/1.1: 持久连接、管道化但队头阻塞。HTTP/2: 多路复用、头部压缩、服务器推送、二进制帧。HTTP/3: QUIC协议(基于UDP)、解决了TCP队头阻塞。',4,NULL,NULL,'medium','system',0,'网络,HTTP',NULL,'2026-03-14 11:35:48.927254','2026-03-14 11:35:48.927254','open',NULL),(42,'TCP和UDP的区别和适用场景？','TCP：面向连接、可靠传输、流量控制、拥塞控制。UDP：无连接、不可靠、实时性好。TCP用于文件传输、网页；UDP用于视频通话、游戏、DNS。',4,NULL,NULL,'easy','system',0,'网络,传输层',NULL,'2026-03-14 11:35:48.928191','2026-03-14 11:35:48.928191','open',NULL),(43,'DNS解析的过程？','本地缓存→本地DNS服务器→根DNS→顶级域DNS→权威DNS。递归查询和迭代查询结合。DNS使用UDP 53端口。',4,NULL,NULL,'medium','system',0,'网络,DNS',NULL,'2026-03-14 11:35:48.929377','2026-03-14 11:35:48.929377','open',NULL),(44,'什么是跨域？如何解决？','同源策略限制不同源的请求。解决方案：CORS（服务端设置Access-Control-Allow-Origin）、JSONP、代理服务器、WebSocket。',4,'腾讯',NULL,'easy','system',0,'网络,前端,安全',NULL,'2026-03-14 11:35:48.930203','2026-03-14 11:35:48.930203','open',NULL),(45,'Cookie、Session、Token的区别？','Cookie: 客户端存储，自动随请求发送。Session: 服务端存储，通过SessionID关联。Token(JWT): 无状态，自包含用户信息，适合分布式系统。',4,NULL,NULL,'medium','system',0,'网络,认证,安全',NULL,'2026-03-14 11:35:48.930991','2026-03-14 11:35:48.930991','open',NULL),(46,'进程和线程的区别？','进程是资源分配单位，线程是CPU调度单位。进程有独立地址空间，线程共享。线程切换开销小。进程间通信需要IPC，线程间共享内存。',4,NULL,NULL,'easy','system',0,'操作系统,基础',NULL,'2026-03-14 11:35:48.931930','2026-03-14 11:35:48.931930','open',NULL),(47,'什么是死锁？如何避免？','四个必要条件：互斥、占有且等待、非抢占、循环等待。预防：破坏任一条件。银行家算法检测死锁。实践中：固定加锁顺序、加超时、减小锁粒度。',4,NULL,NULL,'medium','system',0,'操作系统,并发',NULL,'2026-03-14 11:35:48.932926','2026-03-14 11:35:48.932926','open',NULL),(48,'虚拟内存的原理？页面置换算法有哪些？','虚拟地址→物理地址映射，通过页表实现。页面置换算法：FIFO、LRU（最近最少使用）、LFU（最少使用频率）、OPT（最优）。LRU最常考。',4,NULL,NULL,'hard','system',0,'操作系统,内存管理',NULL,'2026-03-14 11:35:48.933866','2026-03-14 11:35:48.933866','open',NULL),(49,'Linux中常用的进程间通信方式？','管道(pipe)、命名管道(FIFO)、消息队列、共享内存、信号量、Socket、信号。共享内存最快但需同步。',4,NULL,NULL,'medium','system',0,'操作系统,Linux',NULL,'2026-03-14 11:35:48.934872','2026-03-14 11:35:48.934872','open',NULL),(50,'MySQL的事务隔离级别有哪些？','读未提交、读已提交(RC)、可重复读(RR, MySQL默认)、串行化。RR通过MVCC+Next-Key Lock解决幻读。RC每次读取最新快照。',4,'阿里巴巴',NULL,'medium','system',0,'MySQL,事务',NULL,'2026-03-14 11:35:48.935703','2026-03-14 11:35:48.935703','open',NULL),(51,'什么是索引？MySQL中索引的类型？','索引是帮助数据库高效查找数据的数据结构。B+树索引（主键索引、唯一索引、普通索引）、哈希索引、全文索引。聚簇索引vs非聚簇索引。',4,NULL,NULL,'easy','system',0,'MySQL,索引',NULL,'2026-03-14 11:35:48.936453','2026-03-14 11:35:48.936453','open',NULL),(52,'SQL优化的常见策略？','1)分析慢查询(EXPLAIN) 2)建立合适索引 3)避免SELECT * 4)分页优化 5)避免在WHERE中对字段进行函数操作 6)使用覆盖索引 7)大表分库分表',4,NULL,NULL,'medium','system',0,'MySQL,性能优化',NULL,'2026-03-14 11:35:48.937493','2026-03-14 11:35:48.937493','open',NULL),(53,'什么是MVCC？它是如何工作的？','多版本并发控制。每行数据有隐藏列(事务ID、回滚指针)。读操作读取快照(undo log)而不加锁。不同隔离级别快照时机不同。',4,'字节跳动',NULL,'hard','system',0,'MySQL,事务,并发',NULL,'2026-03-14 11:35:48.938386','2026-03-14 11:35:48.938386','open',NULL),(54,'Redis有哪些数据类型？各自的应用场景？','String(缓存/计数器)、List(消息队列)、Hash(对象存储)、Set(去重/交集)、ZSet(排行榜)。高级：Bitmap、HyperLogLog、Stream。',4,NULL,NULL,'medium','system',0,'Redis,缓存',NULL,'2026-03-14 11:35:48.939276','2026-03-14 11:35:48.939276','open',NULL),(55,'Redis的持久化机制有哪些？','RDB(快照)：fork子进程，定时全量持久化，恢复快但可能丢失数据。AOF：追加写命令日志，数据安全但文件大。4.0+混合持久化。',4,NULL,NULL,'medium','system',0,'Redis,持久化',NULL,'2026-03-14 11:35:48.940161','2026-03-14 11:35:48.940161','open',NULL),(56,'如何设计一个秒杀系统？','前端：按钮防抖、CDN静态化、答题验证码。后端：接口限流、Redis预减库存、消息队列异步下单、分布式锁防超卖。数据库：乐观锁。',5,'阿里巴巴',NULL,'hard','system',0,'系统设计,高并发',NULL,'2026-03-14 11:35:48.941032','2026-03-14 11:35:48.941032','open',NULL),(57,'如何设计一个消息推送系统？','推模式vs拉模式vs推拉结合。WebSocket长连接、消息队列(RabbitMQ/Kafka)、离线消息存储、消息ACK确认、已读未读状态。',5,NULL,NULL,'hard','system',0,'系统设计,消息系统',NULL,'2026-03-14 11:35:48.947583','2026-03-14 11:35:48.947583','open',NULL),(58,'如何设计一个全文搜索引擎？','倒排索引（分词→建立term到doc的映射）、TF-IDF相关性排序、布尔查询、高亮、分页。实践中用Elasticsearch。',5,NULL,NULL,'hard','system',0,'系统设计,搜索',NULL,'2026-03-14 11:35:48.948757','2026-03-14 11:35:48.948757','open',NULL),(59,'微服务和单体架构的优缺点？','单体：简单、部署方便但耦合高、扩展性差。微服务：独立部署/扩展/技术选型，但复杂度高（服务发现、分布式事务、链路追踪）。',5,NULL,NULL,'medium','system',0,'系统设计,架构',NULL,'2026-03-14 11:35:48.951326','2026-03-14 11:35:48.951326','open',NULL),(60,'如何实现LRU缓存？','哈希表+双向链表。get/put均为O(1)。get时移到链表头部，put时若满则删尾部节点。Java中LinkedHashMap可直接实现。',4,'字节跳动',NULL,'hard','system',0,'算法,缓存,数据结构',NULL,'2026-03-14 11:35:48.952397','2026-03-14 11:35:48.952397','open',NULL),(61,'字节跳动的推荐系统是如何工作的？','召回→粗排→精排→重排。特征工程(用户画像+内容特征)、协同过滤、深度学习模型(DNN/Wide&Deep/DIN)、实时更新。',4,'字节跳动',NULL,'hard','system',0,'推荐系统,机器学习',NULL,'2026-03-14 11:35:48.953322','2026-03-14 11:35:48.953322','open',NULL),(62,'React和Vue的主要区别？','React: JSX、单向数据流、函数式、Hooks、虚拟DOM diff。Vue: 模板语法、双向绑定、响应式系统、组合式API。Vue上手容易，React灵活度高。',4,'字节跳动',NULL,'medium','system',0,'前端,框架',NULL,'2026-03-14 11:35:48.954156','2026-03-14 11:35:48.954156','open',NULL),(63,'JavaScript的事件循环机制？','调用栈→微任务队列(Promise.then/MutationObserver)→宏任务队列(setTimeout/setInterval/I/O)。每次宏任务执行完清空所有微任务。',4,'字节跳动',NULL,'medium','system',0,'JavaScript,前端',NULL,'2026-03-14 11:35:48.954907','2026-03-14 11:35:48.954907','open',NULL),(64,'线程池的核心参数和工作原理？','corePoolSize、maxPoolSize、keepAliveTime、workQueue、handler。任务→核心线程→队列→最大线程→拒绝策略。',4,'腾讯',NULL,'medium','system',0,'Java,并发',NULL,'2026-03-14 11:35:48.955762','2026-03-14 11:35:48.955762','open',NULL),(65,'Spring Boot的自动配置原理？','@EnableAutoConfiguration→spring.factories→条件注解(@ConditionalOnClass等)筛选需要的配置类→Bean注入容器。',4,'腾讯',NULL,'medium','system',0,'Java,Spring',NULL,'2026-03-14 11:35:48.956656','2026-03-14 11:35:48.956656','open',NULL),(66,'分布式系统中如何保证数据一致性？','CAP定理(三选二)。方案：2PC/3PC、TCC、消息队列最终一致性、Saga模式。实践中常用最终一致性。',4,'腾讯',NULL,'hard','system',0,'分布式,一致性',NULL,'2026-03-14 11:35:48.957515','2026-03-14 11:35:48.957515','open',NULL),(67,'WebSocket和HTTP长轮询的区别？','WebSocket: 全双工通信、持久连接、实时推送。长轮询: 客户端发请求、服务端hold住直到有数据返回。WebSocket更高效。',4,'腾讯',NULL,'easy','system',0,'网络,实时通信',NULL,'2026-03-14 11:35:48.958352','2026-03-14 11:35:48.958352','open',NULL),(68,'JVM的内存模型和垃圾回收机制？','堆(年轻代+老年代)、方法区、栈、本地方法栈、程序计数器。GC算法：标记-清除、复制、标记-整理。收集器：Serial、Parallel、CMS、G1、ZGC。',4,'阿里巴巴',NULL,'hard','system',0,'Java,JVM',NULL,'2026-03-14 11:35:48.959270','2026-03-14 11:35:48.959270','open',NULL),(69,'MySQL主从复制的原理？','主库写binlog→从库IO线程拉取binlog→写relay log→SQL线程回放。异步复制、半同步复制、组复制。延迟问题和解决方案。',4,'阿里巴巴',NULL,'medium','system',0,'MySQL,高可用',NULL,'2026-03-14 11:35:48.960093','2026-03-14 11:35:48.960093','open',NULL),(70,'Kafka的高吞吐原因？','1)零拷贝(sendfile) 2)顺序写磁盘 3)批量发送和压缩 4)分区并行 5)页缓存 6)预读和后写。',4,'阿里巴巴',NULL,'hard','system',0,'消息队列,Kafka',NULL,'2026-03-14 11:35:48.960894','2026-03-14 11:35:48.960894','open',NULL),(71,'如何设计一个限流方案？','计数器、滑动窗口、漏桶(恒定速率)、令牌桶(允许突发)。分布式限流用Redis+Lua脚本。Nginx层、网关层、应用层多级限流。',4,'阿里巴巴',NULL,'medium','system',0,'系统设计,高可用',NULL,'2026-03-14 11:35:48.961931','2026-03-14 11:35:48.961931','open',NULL),(72,'介绍一下你在项目中遇到的最大技术挑战','选择有难度的技术问题，描述：问题背景→你的分析思路→尝试的解决方案→最终方案的选择依据→效果。',3,NULL,NULL,'medium','system',0,'项目经验,技术挑战',NULL,'2026-03-14 11:35:48.962999','2026-03-14 11:35:48.962999','open',NULL),(73,'你的项目中是如何做性能优化的？','前端：懒加载、代码分割、CDN、缓存策略、图片优化。后端：数据库索引、缓存(Redis)、连接池、异步处理、SQL优化。',3,NULL,NULL,'medium','system',0,'项目经验,性能优化',NULL,'2026-03-14 11:35:48.963837','2026-03-14 11:35:48.963837','open',NULL),(74,'项目中如何保证代码质量？','Code Review、ESLint/Prettier规范、单元测试、集成测试、CI/CD自动化、TypeScript类型检查、Git分支策略。',3,NULL,NULL,'easy','system',0,'项目经验,工程化',NULL,'2026-03-14 11:35:48.964737','2026-03-14 11:35:48.964737','open',NULL),(75,'你在项目中承担什么角色？如何与团队协作？','明确你的职责（前端/后端/全栈/某模块负责人），描述日常的协作方式（站会、Code Review、技术方案讨论）。',3,NULL,NULL,'easy','system',0,'项目经验,团队协作',NULL,'2026-03-14 11:35:48.965638','2026-03-14 11:35:48.965638','open',NULL),(76,'如果让你重新设计这个项目，你会做出哪些改进？','从架构、技术选型、代码质量、测试覆盖、部署流程等方面反思。展示你的技术视野和持续改进的意识。',3,NULL,NULL,'medium','system',0,'项目经验,架构',NULL,'2026-03-14 11:35:48.966457','2026-03-14 11:35:48.966457','open',NULL),(77,'HTTP状态码301和302的区别是什么？','301 永久重定向，302 临时重定向',4,NULL,NULL,'easy','system',0,'网络,HTTP,选择题',NULL,'2026-03-14 12:04:26.151997','2026-03-14 12:04:26.151997','open',NULL),(78,'HTTP状态码301和302的区别是什么？','301 永久重定向，302 临时重定向',4,NULL,NULL,'easy','system',0,'网络,HTTP,选择题',NULL,'2026-03-14 12:04:26.152593','2026-03-14 12:04:26.152593','open',NULL),(79,'HTTP状态码301和302的区别是什么？','301 永久重定向，302 临时重定向',4,NULL,NULL,'easy','system',0,'网络,HTTP,选择题',NULL,'2026-03-14 12:04:26.152949','2026-03