INSERT INTO `resume_templates` VALUES (1,'简约标准',NULL,'{\"style\": \"minimal\", \"sections\": [\"basicInfo\", \"education\", \"experience\", \"projects\", \"skills\"]}','适合大多数岗位的简洁模板',1,1,'2026-03-12 09:30:16.550751',NULL,NULL,'2026-03-12 09:32:24.437221','通用'),(2,'技术专业',NULL,'{\"style\": \"technical\", \"sections\": [\"basicInfo\", \"skills\", \"projects\", \"experience\", \"education\"]}','突出技术技能和项目经验',1,2,'2026-03-12 09:30:16.552798',NULL,NULL,'2026-03-12 09:32:24.437221','通用'),(3,'创意设计',NULL,'{\"style\": \"creative\", \"sections\": [\"basicInfo\", \"portfolio\", \"experience\", \"skills\", \"education\"]}','适合设计、产品类岗位',1,3,'2026-03-12 09:30:16.553916',NULL,NULL,'2026-03-12 09:32:24.437221','通用'),(4,'专业求职简历',NULL,NULL,'真实简历模板 - 含教育背景/专业技能/实习经历/项目经验/自我评价',0,4,'2026-03-12 09:48:10.841069','<div class=\"resume\"><h1>张三</h1><p>138-0000-0000 | zhangsan@email.com | 北京</p><p>━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━</p><h2>教育背景</h2><p><strong>北京大学</strong>  计算机科学与技术  本科                                                   2021.09 - 2025.06</p><p>GPA: 3.8/4.0  |  专业排名: 前10%</p><h2>专业技能</h2><ul><li>编程语言：熟练掌握 Java、Python、JavaScript/TypeScript，了解 Go、C++</li><li>前端技术：Vue 3、React、Ant Design、Tailwind CSS、Webpack/Vite</li><li>后端技术：Spring Boot、NestJS、Express、RESTful API 设计</li><li>数据库：MySQL、Redis、MongoDB，熟悉 SQL 优化和索引设计</li><li>工具/其他：Git、Docker、Linux、CI/CD、单元测试</li></ul><h2>实习经历</h2><p><strong>字节跳动</strong>  后端开发实习生                                              2024.06 - 2024.09</p><ul><li>负责内容推荐系统的后端服务开发，使用 Go + gRPC 实现微服务架构</li><li>优化推荐接口响应时间，通过 Redis 缓存热点数据，P99 延迟从 200ms 降至 50ms</li><li>设计并实现 A/B 测试框架，支持 1000+ 并发实验组，提升实验效率 60%</li></ul><h2>项目经验</h2><p><strong>校园招聘服务平台</strong>  全栈开发                                              2025.01 - 至今</p><ul><li>基于 NestJS + Vue 3 + MySQL 的全栈校园招聘平台，包含社区论坛、简历管理、投递追踪等模块</li><li>实现 JWT 认证 + RBAC 权限控制，设计 RESTful API 接口 50+</li><li>集成火山方舟 AI 大模型，实现简历智能分析和面试题生成</li><li>使用 Redis 实现验证码缓存和接口限流，保障系统安全</li></ul><h2>自我评价</h2><p>热爱编程，具备良好的算法基础和系统设计能力。拥有大厂实习经验，熟悉敏捷开发流程。性格积极乐观，具有较强的学习能力和团队协作精神。</p></div>','*{margin:0;padding:0;box-sizing:border-box}\nbody{font-family:\'Microsoft YaHei\',sans-serif;color:#333;background:#fff;padding:40px}\n.resume{max-width:800px;margin:0 auto}\nh1{text-align:center;font-size:28px;color:#333;margin-bottom:8px}\nh2{font-size:16px;color:#1677ff;border-bottom:1px solid #e8e8e8;padding-bottom:6px;margin:16px 0 10px}\np{line-height:1.8;font-size:14px;margin-bottom:4px}\nul{padding-left:20px;margin-bottom:10px}\nli{font-size:14px;line-height:1.8;margin-bottom:2px}\nstrong{color:#333}\n@media print{body{padding:20px}@page{margin:15mm}}','2026-03-12 09:48:10.841069','求职');
